def calculate_shipping_cost(price, location):
    # Ví dụ về lồng điều kiện gây khó đọc và bảo trì
    if price > 0:
        if location == "internal":
            if price >= 100:
                return 0
            else:
                return 5
        else:
            return 15
    else:
        return -1

